import '../../../core/logging/logger_service.dart';

class AuthWrapper extends ConsumerStatefulWidget {
  const AuthWrapper({super.key});

  @override
  ConsumerState<AuthWrapper> createState() => _AuthWrapperState();
}

class _AuthWrapperState extends ConsumerState<AuthWrapper> {
  final _logger = LoggerService();
  Timer? _emailVerificationTimer;

  @override
  void initState() {
    super.initState();
    _logger.info('AuthWrapper initialized');
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted) {
        _startEmailVerificationCheck();
      }
    });
  }

  void _startEmailVerificationCheck() {
    _emailVerificationTimer?.cancel();
    _emailVerificationTimer = Timer.periodic(
      const Duration(seconds: 5),
      (_) {
        if (!mounted) return;

        final authState = ref.read(authNotifierProvider);
        final user = authState.user;

        // Only check if we have a non-guest authenticated user who needs verification
        if (authState.status == AuthStatus.authenticated &&
            user != null &&
            !user.isGuest &&
            !user.isEmailVerified &&
            user.email != null) {
          ref.read(authNotifierProvider.notifier).checkEmailVerification();
        }
      },
    );
  }

  @override
  void dispose() {
    _emailVerificationTimer?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final authState = ref.watch(authNotifierProvider);
    _logger.info('Auth status: ${authState.status}');

    return switch (authState.status) {
      AuthStatus.authenticated || AuthStatus.guest => const CardsScreen(),
      AuthStatus.loading => const Scaffold(
          body: Center(child: CircularProgressIndicator()),
        ),
      _ => const LoginScreen(), // includes unauthenticated and error states
    };
  }
}

