  void initState() {
    super.initState();
    _logger.info('Viewing card details: ${widget.card.cardNumber}');
    ref.read(cardCacheServiceProvider).addRecentCard(widget.card);
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(widget.card.name),
        actions: [
