            onPressed: () {
              setState(() {
                _isImageExpanded = !_isImageExpanded;
              });
            },
          ),
        ],
      ),
      body: SingleChildScrollView(
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            Hero(
              tag: 'card_${widget.card.cardNumber}',
